import { ZoneCache, ZuploContext, ZuploRequest } from "@zuplo/runtime";

export default async function (request: ZuploRequest, context: ZuploContext) {
  const cache = new ZoneCache("test-cache", context);
  const cacheKey = request.url;

  context.log.info(`Cache key: ${cacheKey}`);

  // Check if data is in the cache
  const cachedData = await cache.get(cacheKey);
  context.log.info(`Cache hit: ${!!cachedData}`);

  if (cachedData) {
    context.log.info(`Returning cached data`);
    return new Response(JSON.stringify(cachedData), {
      status: 200,
      headers: {
        "Content-Type": "application/json",
        "x-cache": "hit",
      },
    });
  }

  // Cache miss - fetch from the backend
  context.log.info(`Cache miss, fetching from backend`);
  const response = await fetch("https://echo.zuplo.io/");
  const data = await response.json();

  // Store in cache with 60 second TTL
  await cache.put(cacheKey, data, 60);
  context.log.info(`Data cached with key: ${cacheKey}`);

  return new Response(JSON.stringify(data), {
    status: 200,
    headers: {
      "Content-Type": "application/json",
      "x-cache": "miss",
    },
  });
}
